use std::collections::BTreeMap;
use std::f64::consts::PI;
use std::io::{self, Read};

const LT: &str = "LT";
const EQ: &str = "EQ";
const GT: &str = "GT";

fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

fn cmp_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == GT
}

fn cmp_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == LT
}

fn cmp_ge(a: f64, b: f64) -> bool {
    let c = realcompare(a, b);
    c == GT || c == EQ
}

fn cmp_le(a: f64, b: f64) -> bool {
    let c = realcompare(a, b);
    c == LT || c == EQ
}

